import java.time.LocalDate;
public class Main {
    public static void main(String[] args) {
        Hotel h = new Hotel("X");
        h.addRoom("DOUBLE", "201");
        Booking b = h.bookRoom(new Guest("J", "j@x", "1"), "DOUBLE", LocalDate.of(2026,5,10), 2);
        h.checkIn(b);
        h.orderRoomService("201", "Tea", 10.0);
        Bill bill = h.checkOut(b);
        if (bill == null) { System.out.println("FAIL"); System.exit(1); }
        System.out.println(bill.getTotal() > 0 ? "BILL_OK" : "BILL_FAIL");
    }
}
